INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 13020026, "", "存外意義あるものだ\n資材ダイビングとか\nいう新種の探索行は", 111031, "", "", "", 302, 10);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, 13020027, "", 1, 0, "", "", "", 302, "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 11, 13020028, "", "まあ万一溺れたとて\n後輩たちの誰ぞが\nきっと気付くだろう", 111031, "", "", "", 302, 10);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 91, 13020029, "", 1, 0, "", "", "", 302, "");
